          if (this.isPrivateIP(normalizedRemote)) {
            this.logger.error(`Socket connected to private IP: ${remoteIP}`);
            socket.destroy();
            reject(new Error('Connection to private IP blocked'));
          }
        });
      });

      req.end();
    });
  }
}

