// Private/internal IP ranges to block
function isPrivateIP(ip) {
  try {
    const addr = ipaddr.parse(ip);
    const range = addr.range();

    // Block all non-public ranges
    const blockedRanges = [
      'unspecified',
      'broadcast',
      'multicast',
      'linkLocal',
      'loopback',
      'private',
      'reserved',
      'uniqueLocal',
      'ipv4Mapped',
      'rfc6052',
      'rfc6145',
      'rfc6598',
      '6to4',
      'teredo'
    ];

    return blockedRanges.includes(range);
  } catch (e) {
    return true; // Block if IP cannot be parsed
  }
}

async function validateUrl(urlString) {
  // Parse URL strictly
  let parsedUrl;
  try {
    parsedUrl = new URL(urlString);
  } catch (e) {
    throw new Error('Invalid URL format');
  }

  // Protocol validation
  if (!ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
    throw new Error('Protocol not allowed');
  }

  // Block URLs with credentials
  if (parsedUrl.username || parsedUrl.password) {
    throw new Error('URLs with credentials not allowed');
  }

  // Normalize and re-parse to catch parser tricks
  const normalizedUrl = parsedUrl.href;
  const reparsedUrl = new URL(normalizedUrl);

  if (reparsedUrl.hostname !== parsedUrl.hostname) {
    throw new Error('URL normalization mismatch detected');
  }

  // Resolve hostname to IP addresses
  const hostname = parsedUrl.hostname;
  let addresses;

  try {
    // Try parsing as IP first
    if (ipaddr.isValid(hostname)) {
      addresses = [hostname];
    } else {
      // DNS lookup - get all IPs
      const result = await dns.lookup(hostname, { all: true });
      addresses = result.map(r => r.address);
    }
  } catch (e) {
    throw new Error('Failed to resolve hostname');
  }

  // Check ALL resolved IPs
  for (const ip of addresses) {
    if (isPrivateIP(ip)) {
      throw new Error('Internal IP address not allowed');
    }
  }

  return normalizedUrl;
}

