DNS rebinding is a sophisticated attack where the attacker controls a domain with very low TTL, making it resolve to a safe IP during validation but switching to an internal IP milliseconds later when the actual HTTP request is made. This is extremely dangerous and requires multiple defense layers.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const https = require('https');
const http = require('http');
const { URL } = require('url');
const dns = require('dns').promises;
const ipaddr = require('ipaddr.js');
const net = require('net');
const tls = require('tls');

const app = express();
app.use(express.json());

// Configuration
const CONFIG = {
  ALLOWED_PROTOCOLS: ['http:', 'https:'],
  MAX_REDIRECTS: 3,
  REQUEST_TIMEOUT: 10000,
  MAX_RESPONSE_SIZE: 10 * 1024 * 1024, // 10MB
  DNS_CACHE_TTL: 300000, // 5 minutes - ignore attacker's low TTL
  ALLOWED_CONTENT_TYPES: ['text/html', 'application/json', 'text/plain']
};

// DNS cache to prevent rebinding
const dnsCache = new Map();

class SSRFProtector {
  static isPrivateIP(ip) {
    try {
      const addr = ipaddr.parse(ip);
      const range = addr.range();

      const blockedRanges = [
        'unspecified', 'broadcast', 'multicast', 'linkLocal',
        'loopback', 'private', 'reserved', 'uniqueLocal',
        'ipv4Mapped', 'rfc6052', 'rfc6145', 'rfc6598', '6to4', 'teredo'
      ];

      return blockedRanges.includes(range);
    } catch (e) {
      return true;
    }
  }

  static async resolveAndCache(hostname) {
    // Check cache first (prevents DNS rebinding)
    const cached = dnsCache.get(hostname);
    if (cached && Date.now() - cached.timestamp < CONFIG.DNS_CACHE_TTL) {
      return cached.addresses;
    }

    let addresses;

    // Check if hostname is already an IP
    if (ipaddr.isValid(hostname)) {
      addresses = [hostname];
    } else {
      const result = await dns.lookup(hostname, { all: true });
      addresses = result.map(r => r.address);
    }

    // Validate ALL resolved IPs
    for (const ip of addresses) {
      if (this.isPrivateIP(ip)) {
        throw new Error(`Hostname ${hostname} resolves to blocked IP ${ip}`);
      }
    }

    // Cache the safe IPs with our own TTL (ignore attacker's low TTL)
    dnsCache.set(hostname, {
      addresses,
      timestamp: Date.now()
    });

    return addresses;
  }

  static async validateUrl(urlString) {
    let parsedUrl;
    try {
      parsedUrl = new URL(urlString);
    } catch (e) {
      throw new Error('Invalid URL format');
    }

    if (!CONFIG.ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
      throw new Error(`Protocol ${parsedUrl.protocol} not allowed`);
    }

    if (parsedUrl.username || parsedUrl.password) {
      throw new Error('Credentials in URL not allowed');
    }

    // Block numeric ports that might be internal services
    const port = parseInt(parsedUrl.port) || (parsedUrl.protocol === 'https:' ? 443 : 80);
    if (![80, 443, 8080, 8443].includes(port)) {
      throw new Error(`Port ${port} not allowed`);
    }

    // Resolve and validate hostname
    const addresses = await this.resolveAndCache(parsedUrl.hostname);

    return {
      url: parsedUrl.href,
      hostname: parsedUrl.hostname,
      resolvedIPs: addresses,
      port: port,
      protocol: parsedUrl.protocol
    };
  }

  static createSafeAgent(resolvedIPs, port) {
    // Custom agent that connects ONLY to pre-validated IPs
    return {
      createConnection: (options, callback) => {
        // Force connection to our resolved IP, not re-resolved hostname
        const ip = resolvedIPs[0];

        // Final IP check at connection time
        if (this.isPrivateIP(ip)) {
          const err = new Error('Connection to private IP blocked');
          callback(err);
          return;
        }

        const socket = net.createConnection({
          host: ip,
          port: port,
          timeout: CONFIG.REQUEST_TIMEOUT
        }, () => {
          callback(null, socket);
        });

        socket.on('error', callback);
        return socket;
      }
    };
  }

  static async fetchUrl(urlInfo, redirectCount = 0) {
    if (redirectCount > CONFIG.MAX_REDIRECTS) {
      throw new Error('Too many redirects');
    }

    return new Promise((resolve, reject) => {
      const client = urlInfo.protocol === 'https:' ? https : http;

      const options = {
        hostname: urlInfo.resolvedIPs[0], // Connect directly to validated IP
        port: urlInfo.port,
        path: new URL(urlInfo.url).pathname + new URL(urlInfo.url).search,
        method: 'GET',
        timeout: CONFIG.REQUEST_TIMEOUT,
        headers: {
          'Host': urlInfo.hostname, // Set Host header for virtual hosts
          'User-Agent': 'SafeURLFetcher/1.0'
        },
        // Disable TLS hostname verification for IP connection
        // but ensure the certificate is valid for the original hostname
        rejectUnauthorized: true,
        servername: urlInfo.hostname
      };

      const req = client.request(options, async (res) => {
        // Handle redirects with full re-validation
        if ([301, 302, 303, 307, 308].includes(res.statusCode)) {
          const location = res.headers.location;
          if (!location) {
            reject(new Error('Redirect without location header'));
            return;
          }

          // Resolve relative URLs
          const redirectUrl = new URL(location, urlInfo.url).href;

          try {
            // CRITICAL: Re-validate redirect URL completely
            const redirectInfo = await this.validateUrl(redirectUrl);
            console.log(`[SSRF] Following redirect to ${redirectUrl}`);
            const result = await this.fetchUrl(redirectInfo, redirectCount + 1);
            resolve(result);
          } catch (e) {
            reject(new Error(`Redirect blocked: ${e.message}`));
          }
          return;
        }

        // Validate content type
        const contentType = res.headers['content-type'] || '';
        const isAllowed = CONFIG.ALLOWED_CONTENT_TYPES.some(t => 
          contentType.toLowerCase().includes(t)
        );

        if (!isAllowed && contentType) {
          reject(new Error(`Content-Type ${contentType} not allowed`));
          return;
        }

        // Collect response with size limit
        const chunks = [];
        let totalSize = 0;

        res.on('data', (chunk) => {
          totalSize += chunk.length;
          if (totalSize > CONFIG.MAX_RESPONSE_SIZE) {
            req.destroy();
            reject(new Error('Response too large'));
            return;
          }
          chunks.push(chunk);
        });

        res.on('end', () => {
          resolve({
            statusCode: res.statusCode,
            headers: res.headers,
            body: Buffer.concat(chunks).toString('utf8')
          });
        });
      });

      req.on('error', reject);
      req.on('timeout', () => {
        req.destroy();
        reject(new Error('Request timeout'));
      });

      req.end();
    });
  }
}

// Rate limiting
const requestCounts = new Map();
const RATE_LIMIT = 10; // requests per minute per IP

function rateLimit(req, res, next) {
  const clientIP = req.ip;
  const now = Date.now();
  const windowStart = now - 60000;

  const requests = requestCounts.get(clientIP) || [];
  const recentRequests = requests.filter(t => t > windowStart);

  if (recentRequests.length >= RATE_LIMIT) {
    console.warn(`[SSRF] Rate limit exceeded for ${clientIP}`);
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }

  recentRequests.push(now);
  requestCounts.set(clientIP, recentRequests);
  next();
}

